Here is a clean reimplementation from scratch of what the obfuscated code is doing.

It implements an A* pathfinder on a randomly generated grid with:

- configurable grid size
- blocked/open cells
- 8-direction movement
- straight move cost = `traversalCost`
- diagonal move cost = `adjacentCost`
- heuristic = Manhattan or Euclidean
- a maximum iteration cap
- start at top-left
- goal at bottom-right

```javascript
const gridWidth = 20;
const gridHeight = 15;

const config = {
  penalty: "manhattan",   // "manhattan" or anything else => euclidean
  adjacentCost: 1.414,    // diagonal movement cost
  traversalCost: 1,       // orthogonal movement cost
  minIterations: 1000,    // actually used as a max-iteration limit
  clearanceRatio: 0.25    // chance a cell is blocked
};

// Build a random grid: 0 = open, 1 = blocked
function createGrid(width, height, blockedChance) {
  const grid = [];

  for (let y = 0; y < height; y++) {
    const row = [];
    for (let x = 0; x < width; x++) {
      row.push(Math.random() < blockedChance ? 1 : 0);
    }
    grid.push(row);
  }

  return grid;
}

const grid = createGrid(gridWidth, gridHeight, config.clearanceRatio);

const start = { x: 0, y: 0 };
const goal = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start and goal are walkable
grid[start.y][start.x] = 0;
grid[goal.y][goal.x] = 0;

function makeNodeKey(node) {
  return `${node.x},${node.y}`;
}

function parseNodeKey(key) {
  const [x, y] = key.split(",").map(Number);
  return { x, y };
}

function heuristic(a, b) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);

  if (config.penalty === "manhattan") {
    return dx + dy;
  }

  return Math.sqrt(dx * dx + dy * dy);
}

function getNeighbors(node, grid, width, height) {
  const directions = [
    { dx: 0, dy: -1, cost: config.traversalCost },
    { dx: 0, dy: 1, cost: config.traversalCost },
    { dx: -1, dy: 0, cost: config.traversalCost },
    { dx: 1, dy: 0, cost: config.traversalCost },

    { dx: -1, dy: -1, cost: config.adjacentCost },
    { dx: 1, dy: -1, cost: config.adjacentCost },
    { dx: -1, dy: 1, cost: config.adjacentCost },
    { dx: 1, dy: 1, cost: config.adjacentCost }
  ];

  const neighbors = [];

  for (const dir of directions) {
    const x = node.x + dir.dx;
    const y = node.y + dir.dy;

    const inBounds = x >= 0 && x < width && y >= 0 && y < height;
    if (!inBounds) continue;

    if (grid[y][x] === 0) {
      neighbors.push({ x, y, moveCost: dir.cost });
    }
  }

  return neighbors;
}

function reconstructPath(cameFrom, currentKey, openSet, closedSet) {
  const path = [];

  while (currentKey) {
    const node =
      openSet[currentKey] ||
      closedSet[currentKey] ||
      parseNodeKey(currentKey);

    path.push(node);
    currentKey = cameFrom[currentKey];
  }

  return path;
}

function findRoute(start, goal, grid, width, height, config) {
  const startKey = makeNodeKey(start);

  const openSet = {
    [startKey]: start
  };

  const closedSet = {};
  const cameFrom = {};

  const gScore = {
    [startKey]: 0
  };

  const fScore = {
    [startKey]: heuristic(start, goal)
  };

  let iterations = 0;

  while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
    iterations++;

    // Find node in open set with lowest fScore
    let currentKey = null;
    let lowestFScore = Infinity;

    for (const key in openSet) {
      if (fScore[key] < lowestFScore) {
        lowestFScore = fScore[key];
        currentKey = key;
      }
    }

    const current = openSet[currentKey];

    // Goal reached
    if (current.x === goal.x && current.y === goal.y) {
      const path = reconstructPath(cameFrom, currentKey, openSet, closedSet);
      return {
        path,
        cost: gScore[currentKey],
        iterations
      };
    }

    delete openSet[currentKey];
    closedSet[currentKey] = current;

    const neighbors = getNeighbors(current, grid, width, height);

    for (const neighbor of neighbors) {
      const neighborKey = makeNodeKey(neighbor);

      if (closedSet[neighborKey]) {
        continue;
      }

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + heuristic(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  return {
    path: [],
    cost: Infinity,
    iterations
  };
}

const result = findRoute(start, goal, grid, gridWidth, gridHeight, config);

console.log(
  "Path length:",
  result.path.length,
  "Cost:",
  result.cost,
  "Iterations:",
  result.iterations
);
```

### Notes about behavior preserved from the original

- `minIterations` is misleadingly named in the obfuscated code: it is actually a **maximum iteration limit**, and I preserved that behavior.
- The returned `path` is ordered from **goal back to start**, because that is how the original reconstruction works.
- Diagonal movement is allowed even if it “cuts corners” past blocked orthogonal cells; the original code does not prevent that.
- Grid cells use:
  - `0` = walkable
  - `1` = blocked

